1	import { describe, it, expect } from "vitest";
2	import { processScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // Quote: base premiums
6	  it("should return 5 G premium for an empty item list (processing fee only)", () => {
7	    const scenario = {
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote" as const, items: [] }],
10	    };
11	    const result = processScenario(scenario);
12	    expect(result.results[0]).toEqual({ premium: 5 });
13	  });
14	  it.todo("should return 105 G premium for a single sword (100 base + 5 fee)");
15	  it.todo("should return 65 G premium for a single amulet (60 base + 5 fee)");
16	  it.todo("should return 85 G premium for a single staff (80 base + 5 fee)");
17	  it.todo("should return 45 G premium for a single potion (40 base + 5 fee)");
18	  it.todo("should return 30 G premium for a single rune component (25 base + 5 fee)");
19	  it.todo("should return 165 G premium for a sword and an amulet (100 + 60 base + 5 fee)");
20	
21	  // Quote: component block pricing
22	  it.todo("should return 55 G premium for 2 runes (2 * 25 = 50 base + 5 fee)");
23	  it.todo("should return 65 G premium for 3 runes (block of 3 alike = 60 base + 5 fee)");
24	  it.todo("should return 105 G premium for 4 runes (no block, 4 * 25 = 100 base + 5 fee)");
25	  it.todo("should return 80 G premium for 2 runes + 1 moonstone (no block, different types, 75 base + 5 fee)");
26	  it.todo("should return 125 G premium for 3 runes + 3 moonstones (two blocks, 60 + 60 = 120 base + 5 fee)");
27	
28	  // Quote: item-specific modifiers
29	  it.todo("should add 50% curse surcharge to a cursed sword (100 + 50 = 150 base + 5 fee = 155 G)");
30	  it.todo("should add 30% high-enchantment surcharge for enchantment >= 5 (100 + 30 = 130 base + 5 fee = 135 G)");
31	  it.todo("should apply both curse and high-enchantment surcharges on same item (100 + 50 + 30 = 180 base + 5 fee = 185 G)");
32	  it.todo("should apply item-specific modifiers only to the affected item in a multi-item policy");
33	
34	  // Quote: policy-wide modifiers
35	  it.todo("should apply 10% first-insurance surcharge to every quote (100 + 10 = 110 base + 5 fee = 115 G)");
36	  it.todo("should apply 20% loyalty discount for customers with >= 2 years (100 - 20 = 80 base + 5 fee = 85 G)");
37	  it.todo("should apply 15% follow-up discount on second and subsequent quotes");
38	
39	  // Quote: modifier stacking and rounding
40	  it.todo("should stack item-specific and policy-wide modifiers correctly (newcomer cursed sword = 165 G)");
41	  it.todo("should stack all modifiers for long-standing customer second contract (cursed enchanted sword = 160 G)");
42	  it.todo("should round premiums up in MHPCO's favor");
43	
44	  // Claim: basic payout
45	  it.todo("should pay damage minus 100 G deductible for a standard item");
46	  it.todo("should reimburse at 50% for items with enchantment >= 8, then apply deductible");
47	  it.todo("should fully reimburse dragon-material items, then apply deductible");
48	  it.todo("should apply 50% rule when item has both enchantment >= 8 and dragon material");
49	  it.todo("should apply deductible per damaged item in a multi-item claim");
50	
51	  // Claim: cap
52	  it.todo("should cap total payout at 2x insurance sum");
53	  it.todo("should track remaining cap across multiple claims on the same policy");
54	
55	  // Claim: components
56	  it.todo("should apply standard reimbursement to components (no enchantment or material)");
57	
58	  // Error handling
59	  it.todo("should reject unknown item types in a quote");
60	  it.todo("should reject claim damage for item not in the policy");
61	  it.todo("should reject negative damage amounts");
62	  it.todo("should reject more damages of a type than items insured");
63	});
64

