interface QuoteStep {
  op: "quote";
  items: unknown[];
}

type Step = QuoteStep;

interface Scenario {
  customer: { yearsWithMHPCO: number };
  steps: Step[];
}

interface QuoteResult {
  premium: number;
}

interface ScenarioOutput {
  results: QuoteResult[];
}

export function processScenario(scenario: Scenario): ScenarioOutput {
  return { results: [{ premium: 5 }] };
}

